INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ペコリーヌとの出会い", "フリーマーケット会場", 1, 2834, 91002, 2, 40, 20063115, 7, "フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", 10118, 5118061, 0, "青空の下で謁見", 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("マホとの出会い", "フリーマーケット会場", 1, 2835, 91002, 2, 40, 20063115, 7, "ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", 10118, 5118062, 0, "未来の騎空団\nマスコット？", 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("アキノとの出会い", "ランドソル市街地", 1, 2837, 91002, 2, 40, 20063115, 7, "ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", 10118, 5118063, 0, "お嬢さまからの\n緊急依頼", 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ジュンとの出会い", "フリーマーケット会場", 1, 4108402, 91002, 2, 40, 20063115, 18, "ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", 10118, 5118064, 0, "黄金色の悩みごと", 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("カオリとの出会い", "フリーマーケット会場", 1, 4107402, 91002, 2, 40, 20063115, 18, "フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", 10118, 5118065, 0, "白熱！　格闘大会！", 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ニノンとの出会い", "オーエド町", 1, 9000227, 91002, 2, 40, 20063115, 16, "太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", 10118, 5118066, 1, "祭り太鼓はオーエドの華", 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("スズナとの出会い", "フリーマーケット会場", 1, 2101181, 91002, 3, 40, 20063115, 19, "ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", 10118, 5118067, 0, "人気者は遅れて\nやってくる", 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ナナカとの出会い", "ランドソル市街地", 1, 4109402, 91002, 3, 40, 20063115, 18, "ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", 10118, 5118068, 0, "巫女・ミーツ・魔法少女", 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("キャル＆コッコロとの出会い", "フリーマーケット会場", 1, 4305402, 91002, 3, 40, 20063115, 18, "ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", 10118, 5118069, 0, "ネズ耳は二度なくなる", 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ユカリとの出会い", "ランドソル市街地", 1, 4101402, 91002, 3, 40, 20063115, 18, "街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", 10118, 5118070, 0, "この出会いにカンパイ！", 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("アオイとの出会い", "ランドソル市街地", 1, 4106402, 91002, 3, 40, 20063115, 18, "ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", 10118, 5118071, 0, "陰陽アンサンブル", 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("シノブとの出会い", "フリーマーケット会場", 1, 2836, 91002, 3, 40, 20063115, 7, "ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", 10118, 5118072, 1, "運試し十番勝負！", 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("オープニング", 0, 0, 0, 0, 1, 0, 20063115, 0, 0, 10118, 5118600, 0, "彼女たちの新たな日常", 0);
